mapper.select:
SELECT A.ID, A.NEW_PROCESS, A.IS_CONFIRM, A.PARENT_ID, A.PROCESS_CD, A.PROCESS_NM, A.PROCESS_CD AS CD, A.PROCESS_NM AS NM, A.PLAN_TYPE_CD, A.PLAN_TYPE_NM, A.SHORT_CD, A.PROCESS_TYPE_CD, A.IN_OUT_PORT_TYPE_CD, A.IS_SELECT_SUBTICKET, A.IS_FRONTIER, CASE A.IS_FRONTIER WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_FRONTIER_NM, A.IS_MEANWHILE, CASE A.IS_MEANWHILE WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_MEANWHILE_NM, A.IS_DISPATCH_TALLY_SH, CASE A.IS_DISPATCH_TALLY_SH WHEN '1' THEN '调度室' WHEN '2' THEN '库场队' ELSE NULL END IS_DISPATCH_TALLY_SH_NM, CASE A.IS_SELECT_SUBTICKET WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_SELECT_SUBTICKET_NM, A.IS_TALLY_COURSE, CASE A.IS_TALLY_COURSE WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_TALLY_COURSE_NM, A.IS_MERGE_TICKET, CASE A.IS_MERGE_TICKET WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_MERGE_TICKET_NM, A.IS_CREATE_TICKET, CASE A.IS_CREATE_TICKET WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_CREATE_TICKET_NM, A.IS_DIRECT_ACCESS, CASE A.IS_DIRECT_ACCESS WHEN '1' THEN '是' WHEN '0' THEN '否' ELSE NULL END IS_DIRECT_ACCESS_NM, A.IS_DISPATCH_TALLY, CASE A.IS_DISPATCH_TALLY WHEN '1' THEN '调度室' WHEN '2' THEN '库场队' ELSE NULL END IS_DISPATCH_TALLY_NM, A.TALLY_DATA_STAT, CASE A.TALLY_DATA_STAT WHEN '10' THEN '集疏港' WHEN '20' THEN '直取' WHEN '30' THEN '倒运' ELSE NULL END TALLY_DATA_STAT_NM, A.IS_TAKE, A.SOURCE_CD, A.TARGET_CD, A.SOURCE_NM, A.TARGET_NM, A.IS_TALLY_TON, A.IS_OPERATION_TON, A.IS_THROUGHPUT, A.IS_NATURAL_TON, A.IS_SETTLE, A.IS_PRE_PROCESS, A.UPDATE_POINT, A.IN_OUT_STORAGE_TYPE_CD, A.SORT_NUM, A.REMARK, A.CREATE_BY_NAME, A.IS_CARGO_PACKAGE_CHANGE, CASE A.IS_CARGO_PACKAGE_CHANGE WHEN '1' THEN '是' ELSE '否' END IS_CARGO_PACKAGE_CHANGE_LABEL, B.DICT_LABEL processTypeNm, D.DICT_LABEL inOutPortTypeNm, E.DICT_LABEL isTallyTonLabel, F.DICT_LABEL isOperationTonLabel, G.DICT_LABEL isThroughputLabel, H.DICT_LABEL isNaturalTonLabel, J.DICT_LABEL inOutStorageTypeNm, M.DICT_LABEL sourceNm, N.DICT_LABEL targetNm, I.DICT_LABEL isSettleLabel, K.DICT_LABEL isPreProcessLabel FROM M_WORK_PROCESS A LEFT JOIN M_DICT_DATA B ON B.DICT_VALUE = A.PROCESS_TYPE_CD AND B.DICT_TYPE = 'PROCESS_TYPE' LEFT JOIN M_DICT_DATA D ON D.DICT_VALUE = A.IN_OUT_PORT_TYPE_CD AND D.DICT_TYPE = 'IN_OUT_PORT_TYPE' LEFT JOIN M_DICT_DATA E ON E.DICT_VALUE = A.IS_TALLY_TON AND E.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA F ON F.DICT_VALUE = A.IS_OPERATION_TON AND F.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA G ON G.DICT_VALUE = A.IS_THROUGHPUT AND G.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA H ON H.DICT_VALUE = A.IS_NATURAL_TON AND H.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA I ON I.DICT_VALUE = A.IS_SETTLE AND I.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA K ON K.DICT_VALUE = A.IS_PRE_PROCESS AND K.DICT_TYPE = 'IS' LEFT JOIN M_DICT_DATA J ON J.DICT_VALUE = A.IN_OUT_STORAGE_TYPE_CD AND J.DICT_TYPE = 'IN_OUT_STORAGE_TYPE' LEFT JOIN M_DICT_DATA M ON M.DICT_VALUE = A.SOURCE_CD AND M.DICT_TYPE = 'SOURCE_TARGET_TYPE' LEFT JOIN M_DICT_DATA N ON N.DICT_VALUE = A.TARGET_CD AND N.DICT_TYPE = 'SOURCE_TARGET_TYPE'
and A.ID = #{id}
and A.PARENT_ID = #{parentId}
and A.PROCESS_CD = #{processCd}
and (A.PROCESS_NM LIKE #{processNmLike,jdbcType=VARCHAR} or A.SHORT_CD like #{processNmLike,jdbcType=VARCHAR})
and A.PROCESS_TYPE_CD = #{processTypeCd}
and A.IN_OUT_PORT_TYPE_CD = #{inOutPortTypeCd}
and A.IS_SELECT_SUBTICKET = #{isSelectSubticket}
and A.IS_MERGE_TICKET = #{isMergeTicket}
and A.IS_CREATE_TICKET = #{isCreateTicket}
and A.IS_DIRECT_ACCESS = #{isDirectAccess}
and A.TALLY_DATA_STAT = #{tallyDataStat}
and A.IS_DISPATCH_TALLY = #{isDispatchTally}
and A.UPDATE_POINT = #{updatePoint}
and A.IS_TAKE = #{isTake}
and A.SOURCE_CD = #{sourceCd}
and A.TARGET_CD = #{targetCd}
and A.IS_TALLY_TON = #{isTallyTon}
and A.IS_OPERATION_TON = #{isOperationTon}
and A.IS_THROUGHPUT = #{isThroughput}
and A.IS_NATURAL_TON = #{isNaturalTon}
and A.IS_SETTLE = #{isSettle}
and A.IS_PRE_PROCESS = #{isPreProcess}
and A.IN_OUT_STORAGE_TYPE_CD = #{inOutStorageTypeCd}
order by A.SORT_NUM,A.PROCESS_NM
